INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "青空の下で謁見", 7, 2, 2834, "フリーマーケット会場", 8, 40, 91002, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 0, "ペコリーヌとの出会い", 5118061, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "未来の騎空団\nマスコット？", 7, 2, 2835, "フリーマーケット会場", 8, 40, 91002, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 0, "マホとの出会い", 5118062, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "お嬢さまからの\n緊急依頼", 7, 2, 2837, "ランドソル市街地", 8, 40, 91002, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 0, "アキノとの出会い", 5118063, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "黄金色の悩みごと", 18, 2, 4108402, "フリーマーケット会場", 8, 40, 91002, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 0, "ジュンとの出会い", 5118064, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "白熱！　格闘大会！", 18, 2, 4107402, "フリーマーケット会場", 8, 40, 91002, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 0, "カオリとの出会い", 5118065, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "祭り太鼓はオーエドの華", 16, 2, 9000227, "オーエド町", 8, 40, 91002, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 1, "ニノンとの出会い", 5118066, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "人気者は遅れて\nやってくる", 19, 3, 2101181, "フリーマーケット会場", 8, 40, 91002, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 0, "スズナとの出会い", 5118067, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "巫女・ミーツ・魔法少女", 18, 3, 4109402, "ランドソル市街地", 8, 40, 91002, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 0, "ナナカとの出会い", 5118068, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "ネズ耳は二度なくなる", 18, 3, 4305402, "フリーマーケット会場", 8, 40, 91002, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 0, "キャル＆コッコロとの出会い", 5118069, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "この出会いにカンパイ！", 18, 3, 4101402, "ランドソル市街地", 8, 40, 91002, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 0, "ユカリとの出会い", 5118070, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "陰陽アンサンブル", 18, 3, 4106402, "ランドソル市街地", 8, 40, 91002, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 0, "アオイとの出会い", 5118071, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 10118, "運試し十番勝負！", 7, 3, 2836, "フリーマーケット会場", 8, 40, 91002, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 1, "シノブとの出会い", 5118072, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (0, 10118, "彼女たちの新たな日常", 0, 1, 0, 0, 0, 0, 0, 0, 0, "オープニング", 5118600, 20063115);
